mapper.select:
SELECT t.id AS id, t.title AS title, t.direct_owner_type AS directOwnerType, t.direct_owner_id AS directOwnerId, CASE WHEN t.direct_owner_type = 'PROJECT' THEN p.title WHEN t.direct_owner_type = 'GOAL' THEN g.title WHEN t.direct_owner_type = 'NODE' THEN n.title WHEN t.direct_owner_type = 'INDEPENDENT' THEN '独立待办' END AS ownerName, s.status_code AS statusCode, s.status_name AS statusText, t.deadline_time AS deadlineTime, t.update_time AS updateTime FROM mobe_task_item t LEFT JOIN mobe_project p ON t.direct_owner_type = 'PROJECT' AND p.id = t.direct_owner_id AND p.user_id = t.user_id AND p.is_deleted = 0 LEFT JOIN mobe_goal g ON t.direct_owner_type = 'GOAL' AND g.id = t.direct_owner_id AND g.user_id = t.user_id AND g.is_deleted = 0 LEFT JOIN mobe_node n ON t.direct_owner_type = 'NODE' AND n.id = t.direct_owner_id AND n.user_id = t.user_id AND n.is_deleted = 0 LEFT JOIN mobe_task_status s ON s.id = t.current_status_id AND s.is_deleted = 0 WHERE t.user_id = #{userId} AND t.is_deleted = 0
AND t.title LIKE CONCAT('%', #{keyword}, '%')
AND s.status_code = #{statusCode}
AND t.direct_owner_type = #{directOwnerType}
ORDER BY t.update_time DESC, t.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM mobe_task_item t
LEFT JOIN mobe_task_status s
  ON s.id = t.current_status_id
  AND s.is_deleted = 0
WHERE t.user_id = #{userId}
  AND t.is_deleted = 0

  AND t.title LIKE CONCAT('%', #{keyword}, '%')


  AND s.status_code = #{statusCode}


  AND t.direct_owner_type = #{directOwnerType}
